import { arrayify, hexlify } from '@ethersproject/bytes'
import {
    Commitment,
    ConfirmOptions,
    Connection,
    GetLatestBlockhashConfig,
    Keypair,
    Signer as NativeSolanaSigner,
    PublicKey,
    SendOptions,
    Transaction,
    TransactionInstruction,
    TransactionMessage,
    VersionedTransaction,
    sendAndConfirmRawTransaction,
} from '@solana/web3.js'
import * as bip39 from 'bip39'
import { derivePath } from 'ed25519-hd-key'

import {
    Provider,
    SignedTransaction,
    Signer,
    TransactionPending,
    TransactionReceipt,
    TransactionRequest,
} from '@layerzerolabs/lz-core'

import { getECDSAPublicKey } from '../ecdsa'

export interface SolanaPopulatedTransaction {
    instructions: TransactionInstruction[]
    signers?: NativeSolanaSigner[]
    lzSingers?: SolanaSigner[]
    table?: PublicKey
}

export class SolanaSigner implements Signer {
    private readonly keypair: Keypair
    private provider?: Connection
    private ecdsaPrivateKey?: string
    private ecdsaPublicKey?: string

    private constructor(keypair: Keypair, ecdsaPrivateKey?: string) {
        this.keypair = keypair
        this.ecdsaPrivateKey = ecdsaPrivateKey
        if (ecdsaPrivateKey !== undefined) {
            this.ecdsaPublicKey = getECDSAPublicKey(ecdsaPrivateKey)
        }
    }

    static from(source: Keypair): SolanaSigner
    static from(mnemonic: string, path: string): SolanaSigner

    static from(source: Keypair | string, path?: string): SolanaSigner {
        if (source instanceof Keypair) {
            return new this(source)
        } else if (typeof source === 'string') {
            const { ecdsaPrivateKey, keypair } = getKeypair(source, path)
            return new this(keypair, ecdsaPrivateKey)
        } else {
            throw new Error('Invalid parameters')
        }
    }

    get native(): unknown {
        return this.keypair
    }

    connect(provider: Provider): this {
        if (!(provider.native instanceof Connection)) {
            throw new Error('Only @solana/web3.js Connection is supported.')
        }
        this.provider = provider.native
        return this
    }

    async getAddress(): Promise<string> {
        return Promise.resolve(this.keypair.publicKey.toBase58())
    }

    get address(): string {
        return this.publicKey.toBase58()
    }

    get publicKey(): PublicKey {
        return this.keypair.publicKey
    }

    get secretKey(): Uint8Array {
        return this.keypair.secretKey
    }

    get ECDSAPrivateKey(): string {
        if (this.ecdsaPrivateKey === undefined) {
            throw new Error('ECDSA private key is not available')
        }
        return this.ecdsaPrivateKey
    }

    get ECDSAPublicKey(): string {
        if (this.ecdsaPublicKey === undefined) {
            throw new Error('ECDSA public key is not available')
        }
        return this.ecdsaPublicKey
    }

    async sendAndConfirm(transaction: SignedTransaction, opts?: ConfirmOptions): Promise<TransactionReceipt> {
        const provider = this.assertAndGetProvider()
        const stx = arrayify(transaction.signed as string)
        const response = await sendAndConfirmRawTransaction(provider, Buffer.from(stx), opts)
        return TransactionReceipt.from(response)
    }

    async sendTransaction(transaction: SignedTransaction, sendOptions?: SendOptions): Promise<TransactionPending> {
        const provider = this.assertAndGetProvider()
        const stx = arrayify(transaction.signed as string)
        const response = await provider.sendRawTransaction(stx, sendOptions)
        return TransactionPending.from(response)
    }

    async signTransaction(
        transaction: TransactionRequest,
        opts?: Commitment | GetLatestBlockhashConfig
    ): Promise<SignedTransaction> {
        type NativePopulatedTransaction = Parameters<typeof this.buildTxByPopulatedTx>[0]
        const populatedTransaction = transaction.request as NativePopulatedTransaction

        const provider = this.assertAndGetProvider()

        const tx = await this.buildTxByPopulatedTx(populatedTransaction, opts)
        if (isVersionedTransaction(tx)) {
            if (populatedTransaction.signers) {
                tx.sign(populatedTransaction.signers)
            }

            // sign by keypair
            tx.sign([this.keypair])
        } else {
            tx.feePayer = tx.feePayer ?? this.publicKey
            tx.recentBlockhash = (await provider.getLatestBlockhash(opts)).blockhash

            if (populatedTransaction.signers) {
                for (const signer of populatedTransaction.signers) {
                    tx.partialSign(signer)
                }
            }
            if (populatedTransaction.lzSingers) {
                for (const signer of populatedTransaction.lzSingers) {
                    signer.partialSign(tx)
                }
            }
            // sign by keypair
            tx.partialSign(this.keypair)
        }
        const response = hexlify(tx.serialize())
        return SignedTransaction.from(response)
    }

    async signBuffer(_buffer: Uint8Array): Promise<Uint8Array> {
        await Promise.resolve()
        throw new Error('Method not implemented.')
    }

    partialSign(tx: Transaction | VersionedTransaction): void {
        if (isVersionedTransaction(tx)) {
            tx.sign([this.keypair])
        } else {
            tx.partialSign(this.keypair)
        }
    }

    private async buildTxByPopulatedTx(
        populatedTransaction: SolanaPopulatedTransaction,
        commitmentOrConfig?: Commitment | GetLatestBlockhashConfig
    ): Promise<Transaction | VersionedTransaction> {
        const provider = this.assertAndGetProvider()
        const tx = new VersionedTransaction(
            new TransactionMessage({
                payerKey: this.publicKey,
                recentBlockhash: await provider.getLatestBlockhash(commitmentOrConfig).then((r) => r.blockhash),
                instructions: populatedTransaction.instructions,
            }).compileToV0Message()
        )
        return tx
    }

    private assertAndGetProvider(): Connection {
        if (!this.provider) {
            throw new Error('Signer was not connected to a provider, did you forgot to connect to provider?')
        }
        return this.provider
    }
}

function getKeypair(mnemonic: string, path = "m/44'/501'/0'/0'"): { ecdsaPrivateKey: string; keypair: Keypair } {
    const seed = bip39.mnemonicToSeedSync(mnemonic, '') // (mnemonic, password)
    const privateKey = derivePath(path, seed.toString('hex')).key
    return { ecdsaPrivateKey: hexlify(privateKey), keypair: Keypair.fromSeed(privateKey) }
}

/**
 * Check if a transaction object is a VersionedTransaction or not
 * This function is not exported from @coral-xyz/anchor currently.
 * @param tx
 * @returns bool
 */
export const isVersionedTransaction = (tx: Transaction | VersionedTransaction): tx is VersionedTransaction => {
    return 'version' in tx
}
