import { Provider } from './provider'
import { SignedTransaction, TransactionPending, TransactionReceipt, TransactionRequest } from './transaction'

export interface Signer {
    /**
     * Connect to a provider
     * @param provider
     */
    connect(provider: Provider): Signer

    /**
     * Sign a transaction
     * @param transaction
     */
    signTransaction(transaction: TransactionRequest): Promise<SignedTransaction>

    /**
     * Send a transaction
     * @param transaction
     * @param sendOptions
     */
    sendTransaction(transaction: SignedTransaction, sendOptions?: unknown): Promise<TransactionPending>

    /**
     * Send a transaction and wait for confirmation
     * @param transaction
     * @param opts
     */
    sendAndConfirm(transaction: SignedTransaction, opts?: unknown): Promise<TransactionReceipt>

    /**
     * Sign a buffer (e.g. a message hash)
     */
    signBuffer(buffer: Uint8Array): Promise<Uint8Array>

    /**
     * returns the address of the signer
     */
    getAddress(): Promise<string>

    /**
     * Native signer object
     */
    native: unknown
}

export interface Connectable<T> {
    connect<U>(provider: U): T
}

export function isConnectable<T>(obj: unknown): obj is Connectable<T> {
    if (typeof obj !== 'object' || obj === null) return false
    const fn = (obj as { connect?: unknown }).connect
    return typeof fn === 'function' && typeof fn.length === 'number' && fn.length === 1
}
